SELECT AVG(slopeXZ) AS average_slopeXZ
FROM terrain_data
WHERE trType = 1;

SELECT data_id
FROM terrain_data
WHERE slopeXZ BETWEEN 5 AND 10;

SELECT trType, AVG(slopeXZ) AS avg_slope_xz
FROM terrain_data
GROUP BY trType;

SELECT description, common_characteristics
FROM terrain_types
WHERE trType = 1;
